362	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
363	// status (or 128 + signal for abnormal termination).
364	inline auto run_qemu_handback(const std::string& qemu_binary,
365	                              const std::string& elf_path,
366	                              const hybrid_state_v1& state,
367	                              const std::string& shared_mem_path = {},
368	                              uint64_t shared_mem_size = 0) -> int
369	{
370	  const auto port = detail::pick_free_port();
371	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
372	               qemu_binary, port);
373	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
374	                                       shared_mem_path, shared_mem_size);
375	
376	  try {
377	    restore_state_via_gdbstub(port, state, pid);
378	  } catch (const detail::ChildExitedDuringConnect& d) {
379	    return d.status;
380	  } catch (...) {
381	    ::kill(pid, SIGKILL);
382	    int wstat = 0;
383	    ::waitpid(pid, &wstat, 0);
384	    throw;
385	  }
386	
387	  int wstat = 0;
388	  if (::waitpid(pid, &wstat, 0) < 0)
389	    throw std::runtime_error(std::string{"waitpid: "}
390	                             + std::strerror(errno));
391	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
392	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
393	  return -1;
394	}
